import React, { createContext, useContext, useEffect, useMemo, useState } from 'react';
import { ActivityIndicator, Alert, Button, SafeAreaView, StyleSheet, Text, TextInput, View } from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';

const STORAGE_KEYS = {
  token: 'auth_token',
  user: 'auth_user',
};

const AuthContext = createContext(null);

async function saveAuthData(token, user) {
  await AsyncStorage.multiSet([
    [STORAGE_KEYS.token, token],
    [STORAGE_KEYS.user, JSON.stringify(user)],
  ]);
}

async function clearAuthData() {
  await AsyncStorage.multiRemove([STORAGE_KEYS.token, STORAGE_KEYS.user]);
}

async function loadAuthData() {
  const entries = await AsyncStorage.multiGet([STORAGE_KEYS.token, STORAGE_KEYS.user]);
  const token = entries.find(([key]) => key === STORAGE_KEYS.token)?.[1] || null;
  const userRaw = entries.find(([key]) => key === STORAGE_KEYS.user)?.[1] || null;
  const user = userRaw ? JSON.parse(userRaw) : null;
  return { token, user };
}

function AuthProvider({ children }) {
  const [token, setToken] = useState(null);
  const [user, setUser] = useState(null);
  const [isBootstrapping, setIsBootstrapping] = useState(true);

  useEffect(() => {
    let mounted = true;

    (async () => {
      try {
        const stored = await loadAuthData();
        if (!mounted) return;
        setToken(stored.token);
        setUser(stored.user);
      } catch (e) {
        if (mounted) {
          await clearAuthData();
          setToken(null);
          setUser(null);
        }
      } finally {
        if (mounted) setIsBootstrapping(false);
      }
    })();

    return () => {
      mounted = false;
    };
  }, []);

  const signIn = async ({ email, password }) => {
    const trimmedEmail = String(email || '').trim();
    const trimmedPassword = String(password || '');

    if (!trimmedEmail || !trimmedPassword) {
      throw new Error('Email and password are required.');
    }

    const result = await mockLoginApi(trimmedEmail, trimmedPassword);
    await saveAuthData(result.token, result.user);
    setToken(result.token);
    setUser(result.user);
  };

  const signOut = async () => {
    await clearAuthData();
    setToken(null);
    setUser(null);
  };

  const updateUser = async (nextUser) => {
    setUser(nextUser);
    if (token) {
      await AsyncStorage.setItem(STORAGE_KEYS.user, JSON.stringify(nextUser));
    }
  };

  const value = useMemo(
    () => ({
      token,
      user,
      isAuthenticated: Boolean(token),
      isBootstrapping,
      signIn,
      signOut,
      updateUser,
    }),
    [token, user, isBootstrapping]
  );

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
}

function useAuth() {
  const ctx = useContext(AuthContext);
  if (!ctx) throw new Error('useAuth must be used within AuthProvider');
  return ctx;
}

async function mockLoginApi(email, password) {
  await new Promise((resolve) => setTimeout(resolve, 700));

  if (password.length < 4) {
    throw new Error('Invalid credentials.');
  }

  return {
    token: `demo_token_${Date.now()}`,
    user: {
      id: 'user_1',
      name: email.split('@')[0] || 'User',
      email,
    },
  };
}

function AppRoot() {
  return (
    <AuthProvider>
      <AuthGate />
    </AuthProvider>
  );
}

function AuthGate() {
  const { isBootstrapping, isAuthenticated } = useAuth();

  if (isBootstrapping) {
    return (
      <SafeAreaView style={styles.center}>
        <ActivityIndicator size="large" />
        <Text style={styles.loadingText}>Loading session...</Text>
      </SafeAreaView>
    );
  }

  return isAuthenticated ? <HomeScreen /> : <LoginScreen />;
}

function LoginScreen() {
  const { signIn } = useAuth();
  const [email, setEmail] = useState('demo@example.com');
  const [password, setPassword] = useState('password');
  const [loading, setLoading] = useState(false);

  const onSubmit = async () => {
    try {
      setLoading(true);
      await signIn({ email, password });
    } catch (e) {
      Alert.alert('Login failed', e.message || 'Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <SafeAreaView style={styles.screen}>
      <View style={styles.card}>
        <Text style={styles.title}>Sign In</Text>
        <Text style={styles.label}>Email</Text>
        <TextInput
          value={email}
          onChangeText={setEmail}
          autoCapitalize="none"
          keyboardType="email-address"
          style={styles.input}
          placeholder="email@example.com"
        />
        <Text style={styles.label}>Password</Text>
        <TextInput
          value={password}
          onChangeText={setPassword}
          secureTextEntry
          style={styles.input}
          placeholder="••••••••"
        />
        <Button title={loading ? 'Signing in...' : 'Sign In'} onPress={onSubmit} disabled={loading} />
      </View>
    </SafeAreaView>
  );
}

function HomeScreen() {
  const { user, token, signOut } = useAuth();

  return (
    <SafeAreaView style={styles.screen}>
      <View style={styles.card}>
        <Text style={styles.title}>Welcome</Text>
        <Text style={styles.text}>Name: {user?.name}</Text>
        <Text style={styles.text}>Email: {user?.email}</Text>
        <Text style={styles.text} numberOfLines={2}>
          Token: {token}
        </Text>
        <View style={styles.spacer} />
        <Button title="Log Out" onPress={signOut} />
      </View>
    </SafeAreaView>
  );
}

